def factorial(n: int) -> int:
    if n == 0 or n == 1:
        return 1
    def binary_exponentiation_factorial(x):
        result = 1
        for i in range(2, x + 1):
            result *= i
        return result
    return binary_exponentiation_factorial(n)

def factorial(n: int) -> int:
    cache = {0: 1}
    def calculate_factorial(x):
        if x not in cache:
            cache[x] = x * calculate_factorial(x - 1)
        return cache[x]
    return calculate_factorial(n)

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result
